import { useEffect, useRef, useState } from "react";
import gsap from "gsap";
import { Github, Calendar, ArrowRight, ArrowLeft } from "lucide-react";

const projectData = [
  {
    name: "Sawaari",
    description:
      "A comprehensive ride-sharing platform with real-time tracking and payments.",
    tech: ["React", "Node", "Mapbox", "PostgreSQL"],
    image: "/SawaariLogo.png",
    date: "2024",
    link: "https://github.com/theRoutines/Sawaari.git",
  },
  {
    name: "LRU Cache",
    description:
      "Visualizer for LRU cache with hit/miss animations.",
    tech: ["React", "TypeScript", "D3"],
    image: "/LRUlogo.png",
    date: "2023",
    link: "https://github.com/theRoutines/LRU-Cache-Visualizer.git",
  },
  {
    name: "Notes Pro",
    description:
      "Advanced note-taking app with markdown and collaboration.",
    tech: ["Next.js", "Supabase", "Tailwind"],
    image: "/NotesLogo.png",
    date: "2024",
    link: "https://github.com/theRoutines/ChromeExtension.git",
  }

];

const Projects = () => {
  const cardsRef = useRef([]);
  const [active, setActive] = useState(0);

  useEffect(() => {
    animateCards(active);
  }, [active]);

  const animateCards = (index) => {
    cardsRef.current.forEach((card, i) => {
      if (!card) return;

      const offset = i - index;

      if (offset === 0) {
        gsap.to(card, {
          x: 0,
          scale: 1,
          opacity: 1,
          filter: "blur(0px)",
          zIndex: 10,
          duration: 0.8,
          ease: "power3.out",
        });
      } else {
        gsap.to(card, {
          x: offset * 140,
          scale: 0.85,
          opacity: 0.5,
          filter: "blur(6px)",
          zIndex: 10 - Math.abs(offset),
          duration: 0.8,
          ease: "power3.out",
        });
      }
    });
  };

  const nextProject = () => {
    setActive((prev) => (prev + 1) % projectData.length);
  };

  const prevProject = () => {
    setActive((prev) =>
      prev === 0 ? projectData.length - 1 : prev - 1
    );
  };

  return (
    <section className="min-h-screen flex items-center justify-center bg-sand-dune relative overflow-hidden">
      <div className="relative w-full max-w-6xl h-[75vh] flex items-center justify-center">

        {/* Cards */}
        {projectData.map((project, idx) => (
          <div
            key={idx}
            ref={(el) => (cardsRef.current[idx] = el)}
            className="absolute z-10 w-[90%] md:w-[70%] h-full bg-pale-oak rounded-[3rem] 
            shadow-[0_30px_80px_rgba(0,0,0,0.12)] border border-pine-teal/10 overflow-hidden cursor-pointer"
            onClick={nextProject}
          >
            <div className="grid grid-cols-1 lg:grid-cols-2 h-full">

              {/* LEFT */}
              <div className="p-10 flex flex-col justify-between">
                <div className="space-y-6">
                  <div className="flex items-center gap-2 text-pine-teal/40 text-xs uppercase tracking-widest">
                    <Calendar size={16} />
                    {project.date}
                  </div>

                  <h2 className="text-4xl md:text-6xl font-bold text-pine-teal">
                    {project.name}
                  </h2>

                  <p className="text-pine-teal/60 text-lg leading-relaxed">
                    {project.description}
                  </p>

                  <div className="flex flex-wrap gap-2">
                    {project.tech.map((t, i) => (
                      <span
                        key={i}
                        className="px-3 py-1 text-xs border border-pine-teal/20 
                        rounded-full text-pine-teal/60 bg-white/40"
                      >
                        {t}
                      </span>
                    ))}
                  </div>
                </div>

                <a
                  href={project.link}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="flex items-center gap-2 text-pine-teal font-bold group"
                >
                  <Github size={18} className="group-hover:rotate-12 transition" />
                  View Code
                </a>
              </div>

              {/* RIGHT */}
              <div className="flex items-center justify-center p-10 bg-pine-teal/5 relative overflow-hidden">
                <div className="absolute inset-0 bg-gradient-to-tr from-pine-teal/10 to-transparent" />

                <img
                  src={project.image}
                  alt={project.name}
                  className="w-full h-full object-contain z-10 group-hover:scale-110 transition duration-700"
                />
              </div>
            </div>
          </div>
        ))}

        {/* 🔥 PRO NAVIGATION (SIDE BUTTONS) */}
        <div className="absolute inset-0 z-20 flex items-center justify-between px-6 pointer-events-none">

          {/* Prev */}
          <button
            onClick={prevProject}
            className="pointer-events-auto w-14 h-14 rounded-full border border-pine-teal/20 
            flex items-center justify-center text-pine-teal 
            hover:bg-pine-teal hover:text-sand-dune transition-all backdrop-blur-md"
          >
            <ArrowLeft />
          </button>

          {/* Next */}
          <button
            onClick={nextProject}
            className="pointer-events-auto w-14 h-14 rounded-full bg-pine-teal text-sand-dune 
            flex items-center justify-center shadow-lg 
            hover:scale-110 transition-all"
          >
            <ArrowRight />
          </button>

        </div>
      </div>
    </section>
  );
};

export default Projects;

